insert into dolls (slug, name, personality, default_scale) values ('nova', 'Nova', '温柔、耐心，常在奥克兰的夜晚等待', 0.52) on conflict (slug) do update set name = excluded.name, personality = excluded.personality, default_scale = excluded.default_scale;
insert into doll_poses (doll_id, sort_order, image_url) select id, 0, 'assets/dolls/nova/pose_01.png' from dolls where slug = 'nova' on conflict (doll_id, sort_order) do update set image_url = excluded.image_url;
insert into doll_poses (doll_id, sort_order, image_url) select id, 1, 'assets/dolls/nova/pose_02.png' from dolls where slug = 'nova' on conflict (doll_id, sort_order) do update set image_url = excluded.image_url;
insert into backgrounds (slug, name, tags, image_url) values ('auckland_night', 'Auckland Night', array['night', 'city', 'auckland'], 'assets/backgrounds/auckland_night.jpg') on conflict (slug) do update set name = excluded.name, tags = excluded.tags, image_url = excluded.image_url;
insert into backgrounds (slug, name, tags, image_url) values ('coffee_morning', 'Coffee Morning', array['morning', 'coffee', 'indoor'], 'assets/backgrounds/coffee_morning.jpg') on conflict (slug) do update set name = excluded.name, tags = excluded.tags, image_url = excluded.image_url;
insert into backgrounds (slug, name, tags, image_url) values ('rainy_night', 'Rainy Night', array['night', 'rain', 'indoor'], 'assets/backgrounds/rainy_night.jpg') on conflict (slug) do update set name = excluded.name, tags = excluded.tags, image_url = excluded.image_url;
insert into dramas (id, title, doll_id, status) select gen_random_uuid(), 'Nova 的奥克兰之夜', id, 'draft' from dolls where slug = 'nova';
insert into scenes (drama_id, sort_order, background_id, title) select d.id, 1, b.id, 'Waiting for You' from dramas d, backgrounds b where d.title = 'Nova 的奥克兰之夜' and b.slug = 'auckland_night' order by d.created_at desc limit 1 on conflict (drama_id, sort_order) do update set background_id = excluded.background_id, title = excluded.title;
insert into beats (scene_id, sort_order, start_sec, end_sec, subtitle, position, scale, pose_index) select s.id, 1, 0, 3, 'Auckland. 7PM.', 'center', 0.52, 0 from scenes s join dramas d on s.drama_id = d.id where d.title = 'Nova 的奥克兰之夜' and s.sort_order = 1 on conflict (scene_id, sort_order) do update set start_sec = excluded.start_sec, end_sec = excluded.end_sec, subtitle = excluded.subtitle, position = excluded.position, scale = excluded.scale, pose_index = excluded.pose_index;
